    /**
     * @method
     * @name kalshi#fetchOrder
     * @description fetches a single order by id from the kalshi portfolio endpoint
     * @see https://trading-api.readme.io/reference/getorder
     * @param {string} id order id
     * @param {string} [outcome] unified outcome
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // outcome is only a labelling hint here — the request needs just the id, and
            // parseOrder resolves identity cache-only, so don't force a full market scan
            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                (this.loadOutcome(outcome)).join();
            }
            Object response = (this.kalshiPrivateGetPortfolioOrdersOrderId(this.extend(new java.util.HashMap<String, Object>() {{
                put( "order_id", id );
            }}, parameters))).join();
            return this.parseOrder(this.safeValue(response, "order", response));
        });

    }

    /**
     * @ignore
     * @method
     * @name kalshi#parseOrder
     * @description parses a raw kalshi order object into a unified order object
     * @param {object} order the raw order object
     * @param {object} [market] the outcome object the order belongs to
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public Object parseOrder(Object order, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "order_id");
        Object ticker = this.safeString(order, "ticker");
        // a kalshi order is leg-specific: the raw `side` field says which leg ('yes'|'no');
        // the bare ticker is the YES outcome's id, the NO leg is addressed as `<ticker>-NO`
        Object sideLeg = this.safeStringLower(order, "side");
        Object outcomeKey = ticker;
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(sideLeg, "no"))) && Helpers.isTrue((!Helpers.isEqual(ticker, null)))))
        {
            outcomeKey = Helpers.add(ticker, "-NO");
        }
        Object mkt = this.safeOutcome(outcomeKey, ((Object)market));
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object action = this.safeString(order, "action");
        Object side = ((Helpers.isTrue((Helpers.isEqual(action, "buy"))))) ? "buy" : "sell";
        // price in the outcome's own leg: V2 returns *_price_dollars (already dollars),
        // legacy returned yes_price/no_price in cents
        Object labelIsNo = (Helpers.isEqual(this.safeStringUpper(mkt, "label"), "NO"));
        Object dollarsKey = ((Helpers.isTrue((labelIsNo)))) ? "no_price_dollars" : "yes_price_dollars";
        Object centsKey = ((Helpers.isTrue((labelIsNo)))) ? "no_price" : "yes_price";
        Object price = this.safeNumber(order, dollarsKey);
        if (Helpers.isTrue(Helpers.isEqual(price, null)))
        {
            Object priceCents = this.safeNumber(order, centsKey);
            if (Helpers.isTrue(!Helpers.isEqual(priceCents, null)))
            {
                price = Helpers.divide(priceCents, 100);
            }
        }
        // V2 counts are fixed-point (*_count_fp); legacy used count / filled_count
        Object amount = this.safeNumber2(order, "initial_count_fp", "count");
        Object filled = this.safeNumber2(order, "fill_count_fp", "filled_count", 0);
        Object remaining = this.safeNumber(order, "remaining_count_fp");
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(remaining, null))) && Helpers.isTrue((!Helpers.isEqual(amount, null)))) && Helpers.isTrue((!Helpers.isEqual(filled, null)))))
        {
            remaining = Helpers.subtract(amount, filled);
        }
        Object ts = this.parse8601(this.safeString(order, "created_time"));
        final Object finalPrice = price;
        final Object finalAmount = amount;
        final Object finalFilled = filled;
        final Object finalRemaining = remaining;
        return this.safePredictionOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", KalshiCore.this.safeString(order, "client_order_id") );
            put( "info", order );
            put( "timestamp", ts );
            put( "datetime", KalshiCore.this.iso8601(ts) );
            put( "lastTradeTimestamp", null );
            put( "status", status );
            put( "outcome", KalshiCore.this.safeString(mkt, "outcome") );
            put( "outcomeId", KalshiCore.this.safeString2(mkt, "outcomeId", "id") );
            put( "label", KalshiCore.this.safeString(mkt, "label") );
            put( "market", KalshiCore.this.safeString2(mkt, "market", "outcome") );
            put( "type", KalshiCore.this.safeStringLower(order, "type", "limit") );
            put( "timeInForce", "GTC" );
            put( "postOnly", null );
            put( "side", side );
            put( "price", finalPrice );
            put( "stopPrice", null );
            put( "triggerPrice", null );
            put( "average", null );
            put( "amount", finalAmount );
            put( "cost", null );
            put( "filled", finalFilled );
            put( "remaining", finalRemaining );
            put( "fee", null );
            put( "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()) );
        }}, mkt);
    }

    /**
     * @ignore
     * @method
     * @name kalshi#parseOrderStatus
     * @description maps a kalshi order status string to the CCXT unified status vocabulary
     * @param {string} status the raw kalshi order status
     * @returns {string} the unified order status
     */
    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "resting", "open" );
            put( "executed", "closed" );
            put( "canceled", "canceled" );
            put( "pending", "open" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name kalshi#createOrder
     * @description places a limit or market order on kalshi for the given outcome token
     * @see https://trading-api.readme.io/reference/createorder
     * @param {string} outcome unified outcome
     * @param {string} type 'limit' or 'market'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount number of contracts
     * @param {float} [price] limit price in dollars (0–1 range)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object outcome, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcome(outcome)).join();
            Object outcomeObj = this.outcome(outcome);
            Object ticker = this.safeString(Helpers.GetValue(outcomeObj, "info"), "ticker");
            Object isNo = (Helpers.isEqual(Helpers.GetValue(outcomeObj, "label"), "NO"));
            Object isBuy = (Helpers.isEqual(side, "buy"));
            // kalshi V2 (/portfolio/events/orders) quotes the YES leg only: side 'bid' = buy YES,
            // 'ask' = sell YES, price in dollars. a NO order maps to the complementary YES order
            // buy NO @ q == sell YES @ 1-q - flip the book side and the price
            Object bookSide = ((Helpers.isTrue((isBuy)))) ? "bid" : "ask";
            Object yesPrice = price;
            if (Helpers.isTrue(isNo))
            {
                bookSide = ((Helpers.isTrue((isBuy)))) ? "ask" : "bid";
                if (Helpers.isTrue(!Helpers.isEqual(price, null)))
                {
                    yesPrice = this.parseNumber(Precise.stringSub("1", this.numberToString(price)));
                }
            }
            Object isMarket = (Helpers.isEqual(type, "market"));
            Object defaultTif = ((Helpers.isTrue((isMarket)))) ? "immediate_or_cancel" : "good_till_canceled";
            Object timeInForce = null;
            var timeInForceparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "time_in_force", defaultTif);
            timeInForce = ((java.util.List<Object>) timeInForceparametersVariable).get(0);
            parameters = ((java.util.List<Object>) timeInForceparametersVariable).get(1);
            Object stp = null;
            var stpparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "self_trade_prevention_type", "taker_at_cross");
            stp = ((java.util.List<Object>) stpparametersVariable).get(0);
            parameters = ((java.util.List<Object>) stpparametersVariable).get(1);
            final Object finalBookSide = bookSide;
            final Object finalTimeInForce = timeInForce;
            final Object finalStp = stp;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ticker", ticker );
                put( "side", finalBookSide );
                put( "count", KalshiCore.this.numberToString(amount) );
                put( "time_in_force", finalTimeInForce );
                put( "self_trade_prevention_type", finalStp );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(yesPrice, null)))
            {
                Helpers.addElementToObject(request, "price", this.numberToString(yesPrice));
            }
            Object response = (this.kalshiPrivatePostPortfolioEventsOrders(this.extend(request, parameters))).join();
            // the V2 create response is minimal (order_id, fill_count, remaining_count), so backfill
            // the known order details and resolve the status from the remaining count
            Object order = this.parseOrder(response, ((Object)outcomeObj));
            Helpers.addElementToObject(order, "side", side);
            Helpers.addElementToObject(order, "amount", amount);
            Helpers.addElementToObject(order, "price", price);
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(order, "status"), null)))
            {
                Object remaining = this.safeNumber(response, "remaining_count");
                Object resolvedStatus = "open";
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(remaining, null))) && Helpers.isTrue((Helpers.isEqual(remaining, 0)))))
                {
                    resolvedStatus = "closed";
                }
                Helpers.addElementToObject(order, "status", resolvedStatus);
            }
            return order;
        });

    }

    /**
     * @method
     * @name kalshi#cancelOrder
     * @description cancels a single open order by id on kalshi
     * @see https://trading-api.readme.io/reference/cancelorder
     * @param {string} id order id
     * @param {string} [outcome] unified outcome
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                (this.loadOutcome(outcome)).join();
            }
            // v2 cancel: DELETE /portfolio/events/orders/{order_id} (the /portfolio/orders/{id}
            // and /portfolio/orders/batched paths are deprecated v1 endpoints returning 410 Gone)
            Object response = (this.kalshiPrivateDeletePortfolioEventsOrdersOrderId(this.extend(new java.util.HashMap<String, Object>() {{
                put( "order_id", id );
            }}, parameters))).join();
            return this.parseOrder(this.safeDict(response, "order", response));
        });

    }

    /**
     * @method
     * @name kalshi#cancelAllOrders
     * @description cancels all open orders on kalshi, optionally scoped to one outcome ticker
     * @see https://trading-api.readme.io/reference/cancelorders
     * @param {string} [outcome] unified outcome to scope the cancellation to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> cancelAllOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                (this.loadOutcome(outcome)).join();
            }
            // kalshi has no "cancel all" / batch-cancel endpoint (the v1 DELETE /portfolio/orders
            // and /portfolio/orders/batched paths are 410 Gone) — fetch the resting orders and
            // cancel them one by one via the v2 DELETE /portfolio/events/orders/{order_id}
            Object request = new java.util.HashMap<String, Object>() {{
                put( "status", "resting" );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                Object outcomeObj = this.outcome(outcome);
                Helpers.addElementToObject(request, "ticker", this.safeString(Helpers.GetValue(outcomeObj, "info"), "ticker"));
            }
            Object restingResponse = (this.kalshiPrivateGetPortfolioOrders(request)).join();
            Object restingOrders = this.safeList(restingResponse, "orders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object restingOrdersLength = Helpers.getArrayLength(restingOrders);
            Object canceledOrders = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, restingOrdersLength); i++)
            {
                Object orderId = this.safeString(Helpers.GetValue(restingOrders, i), "order_id");
                if (Helpers.isTrue(!Helpers.isEqual(orderId, null)))
                {
                    final Object finalOrderId = orderId;
                    Object response = (this.kalshiPrivateDeletePortfolioEventsOrdersOrderId(this.extend(new java.util.HashMap<String, Object>() {{
                        put( "order_id", finalOrderId );
                    }}, parameters))).join();
                    ((java.util.List<Object>)canceledOrders).add(this.safeDict(response, "order", response));
                }
            }
            return this.parsePredictionOrders(canceledOrders);
        });

    }

    /**
     * @method
     * @name kalshi#fetchEvents
     * @description fetches kalshi events via cursor-paginated /events, filters client-side by query strings, then fetches full event details with nested markets in parallel and caches in this.events
     * @see https://trading-api.readme.io/reference/getevents
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.query] a single query string to filter events by (matches event ticker/title)
     * @param {string[]} [params.queries] multiple query strings (alternative to query)
     * @param {string} [params.status] 'open' | 'closed' | 'settled', defaults to options.defaultEventStatus
     * @param {int} [params.limit] page size per request, defaults to 200
     * @param {int} [params.maxPages] maximum number of event pages to scan, defaults to 50
     * @returns {object[]} an array of event structures
     */
    public java.util.concurrent.CompletableFuture<Object> fetchEvents(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.requireEventQuery(parameters);
            Object queries = this.parseSearchQueries(parameters);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("query", "queries")));
            // map the unified status onto the kalshi event status (open / closed) so it is pushed server-side
            Object requestedStatus = this.safeString(parameters, "status", this.safeString(this.options, "defaultEventStatus", "active"));
            Object status = "open";
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(requestedStatus, "closed"))) || Helpers.isTrue((Helpers.isEqual(requestedStatus, "inactive")))))
            {
                status = "closed";
            }
            Object pageLimit = this.safeInteger(parameters, "limit", this.safeInteger(this.options, "defaultFetchEventsLimit", 200));
            Object maxPages = this.safeInteger(parameters, "maxPages", 50);
            Object rest = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("status", "limit", "maxPages", "sort", "searchIn", "eventId", "slug")));
            if (!Helpers.isTrue(this.events))
            {
                this.events = new java.util.HashMap<String, Object>() {{}};
            }
            if (!Helpers.isTrue(this.markets))
            {
                this.markets = this.createSafeDictionary();
            }
            Object lowerQueries = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var qi = 0; Helpers.isLessThan(qi, Helpers.getArrayLength(queries)); qi++)
            {
                ((java.util.List<Object>)lowerQueries).add(((String)Helpers.GetValue(queries, qi)).toLowerCase());
            }
            Object lowerQueriesLength = Helpers.getArrayLength(lowerQueries);
            // sequential cursor scan over events ONLY (no nested markets): a nested page is ~2.6 MB
            // 200 events + ~1200 markets - scanning every open event that way transfers tens of MB
            // and takes ~100s. Event-only pages are ~25x smaller; the few events that match the query
            // then fetch their markets individually below (the per-event fallback). Net: seconds, not minutes.
            Object matchedEvents = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object cursor = null;
            Object page = 0;
            while (Helpers.isLessThan(page, maxPages))
            {
                final Object finalStatus = status;
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "status", finalStatus );
                    put( "limit", pageLimit );
                    put( "with_nested_markets", false );
                }};
                if (Helpers.isTrue(cursor))
                {
                    Helpers.addElementToObject(request, "cursor", cursor);
                }
                Object response = (this.kalshiPublicGetEvents(this.extend(request, rest))).join();
                Object rawEvents = (java.util.List<Object>)(this.safeList(response, "events", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
                Object rawEventsLength = Helpers.getArrayLength(rawEvents);
                cursor = this.safeString(response, "cursor");
                for (var rei = 0; Helpers.isLessThan(rei, Helpers.getArrayLength(rawEvents)); rei++)
                {
                    Object rawEvent = Helpers.GetValue(rawEvents, rei);
                    Object ticker = this.safeString(rawEvent, "event_ticker", "");
                    Object tickerLower = ((String)ticker).toLowerCase();
                    Object title = ((String)this.safeString(rawEvent, "title", "")).toLowerCase();
                    Object matches = (Helpers.isEqual(lowerQueriesLength, 0));
                    for (var li = 0; Helpers.isLessThan(li, Helpers.getArrayLength(lowerQueries)); li++)
                    {
                        if (Helpers.isTrue(Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(tickerLower, Helpers.GetValue(lowerQueries, li)), Helpers.opNeg(1))) || Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(title, Helpers.GetValue(lowerQueries, li)), Helpers.opNeg(1)))))
                        {
                            matches = true;
                            break;
                        }
                    }
                    if (Helpers.isTrue(Helpers.isTrue(matches) && Helpers.isTrue(ticker)))
                    {
                        ((java.util.List<Object>)matchedEvents).add(rawEvent);
                    }
                }
                page = this.sum(page, 1);
                if (Helpers.isTrue(!Helpers.isTrue(cursor) || Helpers.isTrue(Helpers.isLessThan(rawEventsLength, pageLimit))))
                {
                    break;
                }
            }
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var di = 0; Helpers.isLessThan(di, Helpers.getArrayLength(matchedEvents)); di++)
            {
                Object fullEvent = Helpers.GetValue(matchedEvents, di);
                Object rawNestedMarkets = (java.util.List<Object>)(this.safeList(fullEvent, "markets", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
                Object rawNestedMarketsLength = Helpers.getArrayLength(rawNestedMarkets);
                if (Helpers.isTrue(Helpers.isEqual(rawNestedMarketsLength, 0)))
                {
                    Object eventTicker = this.safeString(fullEvent, "event_ticker");
                    if (Helpers.isTrue(!Helpers.isEqual(eventTicker, null)))
                    {
                        Object eventMarkets = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                        Object marketCursor = null;
                        Object marketsLimit = this.safeInteger(this.options, "maxFetchMarketsLimit", 1000);
                        Object maxMarketPages = this.safeInteger(this.options, "maxMarketPages", 1000);
                        for (var mp = 0; Helpers.isLessThan(mp, maxMarketPages); mp++)
                        {
                            final Object finalEventTicker = eventTicker;
                            Object marketRequest = new java.util.HashMap<String, Object>() {{
                                put( "event_ticker", finalEventTicker );
                                put( "limit", marketsLimit );
                            }};
                            if (Helpers.isTrue(!Helpers.isEqual(marketCursor, null)))
                            {
                                Helpers.addElementToObject(marketRequest, "cursor", marketCursor);
                            }
                            Object marketResponse = (this.kalshiPublicGetMarkets(marketRequest)).join();
                            Object pageMarkets = (java.util.List<Object>)(this.safeList(marketResponse, "markets", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
                            Object pageMarketsLength = Helpers.getArrayLength(pageMarkets);
                            for (var mi = 0; Helpers.isLessThan(mi, Helpers.getArrayLength(pageMarkets)); mi++)
                            {
                                ((java.util.List<Object>)eventMarkets).add(Helpers.GetValue(pageMarkets, mi));
                            }
                            marketCursor = this.safeString(marketResponse, "cursor");
                            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(marketCursor, null))) || Helpers.isTrue((Helpers.isEqual(marketCursor, "")))) || Helpers.isTrue((Helpers.isLessThan(pageMarketsLength, marketsLimit)))))
                            {
                                break;
                            }
                        }
                        Helpers.addElementToObject(fullEvent, "markets", eventMarkets);
                    }
                }
                Object parsedEvent = this.parseEvent(fullEvent);
                Object eventTitle = this.safeString(fullEvent, "title");
                Object eventKey = ((Helpers.isTrue(eventTitle))) ? this.shortenSlug(eventTitle) : null;
                if (Helpers.isTrue(eventKey))
                {
                    Helpers.addElementToObject(this.events, eventKey, parsedEvent);
                    ((java.util.List<Object>)result).add(parsedEvent);
                    Object parsedMarketsRaw = Helpers.GetValue(parsedEvent, "markets");
                    Object parsedMarkets = ((Helpers.isTrue((!Helpers.isEqual(parsedMarketsRaw, null))))) ? parsedMarketsRaw : new java.util.ArrayList<Object>(java.util.Arrays.asList());
                    for (var mi = 0; Helpers.isLessThan(mi, Helpers.getArrayLength(parsedMarkets)); mi++)
                    {
                        Object m = Helpers.GetValue(parsedMarkets, mi);
                        Helpers.addElementToObject(this.markets, Helpers.GetValue(m, "symbol"), m);
                    }
                }
            }
            this.outcomes = new java.util.HashMap<String, Object>() {{}};
            this.outcomes_by_id = new java.util.HashMap<String, Object>() {{}};
            Object marketKeys = Helpers.objectKeys(this.markets);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketKeys)); i++)
            {
                Object market = Helpers.GetValue(this.markets, Helpers.GetValue(marketKeys, i));
                Object outcomesList = (java.util.List<Object>)(this.safeList(market, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(outcomesList)); j++)
                {
                    Object oc = Helpers.GetValue(outcomesList, j);
                    Object ocSymbol = this.safeString(oc, "outcome");
                    if (Helpers.isTrue(!Helpers.isEqual(ocSymbol, null)))
                    {
                        Helpers.addElementToObject(this.outcomes, ocSymbol, oc);
                    }
                    Object ocId = this.safeString(oc, "outcomeId");
                    if (Helpers.isTrue(!Helpers.isEqual(ocId, null)))
                    {
                        Helpers.addElementToObject(this.outcomes_by_id, ocId, oc);
                    }
                }
            }
            return this.applyEventFetchParams(result, parameters, queries);
        });

    }

    /**
     * @method
     * @name kalshi#fetchEvent
     * @description fetches a single prediction-market event by its event ticker
     * @see https://trading-api.readme.io/reference/getevent
     * @param {string} id the event ticker
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [prediction event structure](https://docs.ccxt.com/#/?id=prediction-event-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchEvent(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object request = new java.util.HashMap<String, Object>() {{
                put( "event_ticker", id );
                put( "with_nested_markets", true );
            }};
            Object response = (this.kalshiPublicGetEventsEventTicker(this.extend(request, parameters))).join();
            Object fullEvent = this.safeDict(response, "event", response);
            Object nestedMarkets = this.safeList(fullEvent, "markets");
            if (Helpers.isTrue(Helpers.isEqual(nestedMarkets, null)))
            {
                Helpers.addElementToObject(fullEvent, "markets", this.safeList(response, "markets", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            }
            Object eventVar = this.parseEvent(fullEvent);
            return eventVar;
        });

    }

    /**
     * @ignore
     * @method
     * @name kalshi#parseEvent
     * @description parses a raw kalshi event object (with nested markets) into the unified CCXT event shape
     * @param {object} rawEvent the raw event object
     * @returns {object} an event structure
     */
    public Object parseEvent(Object rawEvent)
    {
        // {
        //         "available_on_brokers": true,
        //         "category": "Politics",
        //         "collateral_return_type": "",
        //         "event_ticker": "KXBALANCE-29",
        //         "last_updated_ts": "0001-01-01T00:00:00Z",
        //         "markets": [
        //             {
        //                 "can_close_early": true,
        //                 "close_time": "2029-07-01T14:00:00Z",
        //                 "created_time": "0001-01-01T00:00:00Z",
        //                 "early_close_condition": "This market will close and expire early if the event occurs.",
        //                 "event_ticker": "KXBALANCE-29",
        //                 "expected_expiration_time": "2029-07-01T14:00:00Z",
        //                 "expiration_time": "2029-07-01T14:00:00Z",
        //                 "expiration_value": "",
        //                 "fractional_trading_enabled": false,
        //                 "last_price_dollars": "0.1000",
        //                 "latest_expiration_time": "2029-07-01T14:00:00Z",
        //                 "liquidity_dollars": "0.0000",
        //                 "market_type": "binary",
        //                 "no_ask_dollars": "0.9000",
        //                 "no_bid_dollars": "0.8900",
        //                 "no_sub_title": "During Trump's term",
        //                 "notional_value_dollars": "1.0000",
        //                 "open_interest_fp": "16268.00",
        //                 "open_time": "2025-01-03T15:00:00Z",
        //                 "previous_price_dollars": "0.0000",
        //                 "previous_yes_ask_dollars": "0.0000",
        //                 "previous_yes_bid_dollars": "0.0000",
        //                 "price_level_structure": "linear_cent",
        //                 "price_ranges": [
        //                     {
        //                         "end": "1.0000",
        //                         "start": "0.0000",
        //                         "step": "0.0100"
        //                     }
        //                 ],
        //                 "response_price_units": "usd_cent",
        //                 "result": "",
        //                 "rules_primary": "If there is not a budget deficit for any of fiscal years 2025, 2026, 2027, or 2028, then the market resolves to Yes.",
        //                 "rules_secondary": "",
        //                 "settlement_timer_seconds": "1800",
        //                 "status": "active",
        //                 "subtitle": "",
        //                 "tick_size": "1",
        //                 "ticker": "KXBALANCE-29",
        //                 "title": "Will Trump balance the budget?",
        //                 "updated_time": "0001-01-01T00:00:00Z",
        //                 "volume_24h_fp": "28.00",
        //                 "volume_fp": "40111.00",
        //                 "yes_ask_dollars": "0.1100",
        //                 "yes_ask_size_fp": "",
        //                 "yes_bid_dollars": "0.1000",
        //                 "yes_bid_size_fp": "",
        //                 "yes_sub_title": "During Trump's term"
        //             }
        //         ],
        //         "mutually_exclusive": false,
        //         "series_ticker": "KXBALANCE",
        //         "strike_period": "",
        //         "sub_title": "During Trump's term",
        //         "title": "Will Trump balance the budget?"
        // }
        Object rawMarkets = (java.util.List<Object>)(this.safeList(rawEvent, "markets", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object marketsList = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        // aggregate volume/liquidity from the markets and derive the creation time so sort works
        Object totalVolume = 0;
        Object totalLiquidity = 0;
        Object earliestCreated = null;
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawMarkets)); i++)
        {
            Object rawMarket = Helpers.GetValue(rawMarkets, i);
            Object parsed = this.parseMarket(rawMarket);
            ((java.util.List<Object>)marketsList).add(parsed);
            totalVolume = this.sum(totalVolume, this.safeNumber2(rawMarket, "volume_fp", "volume", 0));
            totalLiquidity = this.sum(totalLiquidity, this.safeNumber2(rawMarket, "liquidity_dollars", "liquidity", 0));
            Object marketCreated = this.parse8601(this.safeString(rawMarket, "open_time"));
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(marketCreated, null))) && Helpers.isTrue((Helpers.isTrue((Helpers.isEqual(earliestCreated, null))) || Helpers.isTrue((Helpers.isLessThan(marketCreated, earliestCreated)))))))
            {
                earliestCreated = marketCreated;
            }
        }
        Object ticker = this.safeString(rawEvent, "event_ticker");
        Object title = this.safeString(rawEvent, "title");
        Object created = this.parse8601(this.safeString(rawEvent, "created_date_iso"));
        if (Helpers.isTrue(Helpers.isEqual(created, null)))
        {
            created = earliestCreated;
        }
        final Object finalTotalVolume = totalVolume;
        final Object finalTotalLiquidity = totalLiquidity;
        final Object finalCreated = created;
        return this.extend(new java.util.HashMap<String, Object>() {{
            put( "id", ticker );
            put( "slug", ticker );
            put( "event", ((Helpers.isTrue(title))) ? KalshiCore.this.shortenSlug(title) : null );
            put( "title", title );
            put( "markets", marketsList );
            put( "volume", finalTotalVolume );
            put( "liquidity", finalTotalLiquidity );
            put( "url", KalshiCore.this.safeString(rawEvent, "url") );
            put( "image", KalshiCore.this.safeString(rawEvent, "image_url") );
            put( "created", finalCreated );
            put( "createdDatetime", KalshiCore.this.safeString(rawEvent, "created_date_iso") );
            put( "end", KalshiCore.this.parse8601(KalshiCore.this.safeString(rawEvent, "end_date_iso")) );
            put( "endDatetime", KalshiCore.this.safeString(rawEvent, "end_date_iso") );
            put( "category", KalshiCore.this.safeString(rawEvent, "category") );
            put( "lastUpdatedAt", KalshiCore.this.parse8601(KalshiCore.this.safeString(rawEvent, "last_updated_date_iso")) );
            put( "lastUpdatedAtDatetime", KalshiCore.this.safeString(rawEvent, "last_updated_date_iso") );
            put( "resolutionSource", KalshiCore.this.safeString(rawEvent, "resolution_source") );
            put( "resolved", KalshiCore.this.safeBool(rawEvent, "resolved") );
            put( "info", rawEvent );
        }});
    }

    /**
     * @ignore
     * @method
     * @name kalshi#sign
     * @description builds the request URL and attaches RSA-PSS SHA-256 authentication headers for private endpoints
     * @param {string} path the endpoint path
     * @param {string|string[]} [api] the api group and access level
     * @param {string} [method] HTTP method
     * @param {object} [params] request parameters
     * @param {object} [headers] request headers
     * @param {object} [body] request body
     * @returns {object} a dictionary with url, method, body and headers
     */
    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "kalshi");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object apiGroup = ((Helpers.isTrue((api instanceof String)))) ? api : Helpers.GetValue(api, 0);
        Object access = ((Helpers.isTrue((api instanceof String)))) ? "public" : Helpers.GetValue(api, 1);
        Object baseUrls = Helpers.GetValue(this.urls, "api");
        Object baseUrl = this.safeString(baseUrls, apiGroup, ((String)Helpers.GetValue(baseUrls, "kalshi")));
        Object implodedPath = this.implodeParams(path, parameters);
        Object url = Helpers.add(Helpers.add(baseUrl, "/"), implodedPath);
        Object query = this.omit(parameters, this.extractParams(path));
        Object querystring = this.urlencode(query);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(method, "GET")) && Helpers.isTrue(querystring)))
        {
            url = Helpers.add(url, Helpers.add("?", querystring));
        }
        Object existingHeaders = ((Helpers.isTrue((!Helpers.isEqual(headers, null))))) ? headers : new java.util.HashMap<String, Object>() {{}};
        headers = this.extend(new java.util.HashMap<String, Object>() {{
            put( "Accept", "application/json" );
            put( "Content-Type", "application/json" );
        }}, existingHeaders);
        if (Helpers.isTrue(Helpers.isEqual(access, "private")))
        {
            this.checkRequiredCredentials();
            Object timestamp = String.valueOf(this.milliseconds());
            // Signing payload: {timestamp}{METHOD}{path}, where path is the full request path
            // INCLUDING the /trade-api/v2 prefix and any path params substituted in, but NOT
            // the query string (e.g. /trade-api/v2/portfolio/orders/{order_id})
            Object tradeApiIndex = Helpers.getIndexOf(baseUrl, "/trade-api");
            Object versionPrefix = Helpers.slice(baseUrl, tradeApiIndex, null);
            Object pathForSigning = Helpers.add(Helpers.add(versionPrefix, "/"), implodedPath);
            Object payload = Helpers.add(Helpers.add(timestamp, method), pathForSigning);
            // RSA-PSS SHA-256 signature with the private key PEM
            Object keyParts = Helpers.split(this.privateKey, "\n");
            Object cleanPrivateKey = String.join((String)"\n", (java.util.List<String>)keyParts);
            Object signature = rsa(payload, cleanPrivateKey, sha256(), "pss");
            final Object finalTimestamp = timestamp;
            headers = this.extend(headers, new java.util.HashMap<String, Object>() {{
                put( "KALSHI-ACCESS-KEY", KalshiCore.this.apiKey );
                put( "KALSHI-ACCESS-SIGNATURE", signature );
                put( "KALSHI-ACCESS-TIMESTAMP", finalTimestamp );
            }});
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(method, "GET")) && Helpers.isTrue(querystring)))
            {
                // kalshi expects a JSON body; the signature covers only timestamp+method+path
                body = this.json(query);
            }
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }
